def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 10):
            term = ((-1)**j) * (ratio ** j) / j
            if j % 2 == 0:
                term *= 1.5
            else:
                term *= 0.75
            score += term
        if capacity < item * 1.2:
            score *= 3
        elif capacity < item * 2:
            score *= 1.5
        elif capacity > item * 4:
            score /= 3
        elif capacity > item * 3:
            score /= 1.5
        for k in range(1, 4):
            if (capacity - item * k) < 0:
                score += (k * 0.1)
            else:
                score -= (k * 0.05)
        if abs(capacity - item) < 0.1 * item:
            score *= 2
        priorities[i] = -score
    return priorities
